// ============================================================
// INJECTION LOGIC
// ============================================================

function injectSEO(filePath, lang, seoData) {
  let content = readFileSync(filePath, "utf-8");
  const json = JSON.parse(content);

  for (const [path, seoBlock] of Object.entries(seoData)) {
    const parts = path.split(".");
    let target = json;
    for (const part of parts) {
      if (!target[part]) {
        console.error(`Missing path ${path} in ${filePath}`);
        break;
      }
      target = target[part];
    }
    if (target) {
      target.seo = seoBlock;
    }
  }

  writeFileSync(filePath, JSON.stringify(json, null, 2) + "\n", "utf-8");
  console.log(`Injected SEO into ${filePath}`);
}

// Run injection
const langData = {
  "fr.json": FR_SEO,
  "en.json": EN_SEO,
  "de.json": DE_SEO,
  "pt.json": PT_SEO,
  "lb.json": LB_SEO,
};

for (const [file, seo] of Object.entries(langData)) {
  injectSEO(join(MESSAGES_DIR, file), file, seo);
}

console.log("All SEO translations injected successfully!");
